const msg = $input.first().json;
const message = msg.message || {};
const text = message.text || '';
const from = message.from || {};
const chat = message.chat || {};

const isStartCommand = text.toLowerCase().startsWith('/start');
const isHelpCommand = text.toLowerCase().startsWith('/help') || text.toLowerCase().startsWith('/yardim');

return [{
  json: {
    chatId: chat.id,
    userId: from.id,
    kullaniciAdi: from.username || `${from.first_name || ''} ${from.last_name || ''}`.trim() || 'Anonim',
    mesaj: text,
    mesajId: message.message_id,
    tarih: new Date().toLocaleDateString('tr-TR'),
    saat: new Date().toLocaleTimeString('tr-TR'),
    isCommand: isStartCommand || isHelpCommand,
    commandType: isStartCommand ? 'start' : isHelpCommand ? 'help' : 'message'
  }
}];

