const aiResponse = $input.first().json.candidates?.[0]?.content?.parts?.[0]?.text || '';
const prevData = $('Mesaj Bilgilerini Çıkar').first().json;

const kategoriMatch = aiResponse.match(/\[KATEGORİ:\s*(.+?)\]/i);
const aciliyetMatch = aiResponse.match(/\[ACİLİYET:\s*(.+?)\]/i);

const kategori = kategoriMatch ? kategoriMatch[1].trim() : 'Diğer';
const aciliyet = aciliyetMatch ? aciliyetMatch[1].trim() : 'Düşük';

let temizYanit = aiResponse
  .replace(/\[KATEGORİ:\s*.+?\]/gi, '')
  .replace(/\[ACİLİYET:\s*.+?\]/gi, '')
  .trim();

return [{
  json: {
    chatId: prevData.chatId,
    kullaniciAdi: prevData.kullaniciAdi,
    orijinalMesaj: prevData.mesaj,
    aiYanit: temizYanit,
    kategori,
    aciliyet,
    tarih: prevData.tarih,
    saat: prevData.saat,
    telegramYanit: `${temizYanit}\n\n📋 Kategori: ${kategori}\n⚡ Aciliyet: ${aciliyet}`
  }
}];
